package dashboard

const PageHTML = `<!doctype html><html><head><meta charset="utf-8"><title>RouteFast Mini Dashboard</title><style>body{font-family:Arial,sans-serif;background:#0f172a;color:#e2e8f0;margin:0}.wrap{max-width:1100px;margin:0 auto;padding:20px}.card{background:#111827;border:1px solid #334155;border-radius:14px;padding:16px;margin-top:16px}button{background:#2563eb;color:#fff;border:0;border-radius:8px;padding:8px 12px;cursor:pointer}pre{background:#020617;padding:12px;border-radius:10px;overflow:auto;white-space:pre-wrap}table{width:100%;border-collapse:collapse}td,th{padding:8px;border-bottom:1px solid #334155;text-align:left}</style></head><body><div class="wrap"><h1>RouteFast Mini Dashboard</h1><div><button onclick="pollNow()">Poll peers</button> <button onclick="runDemo()">Run demo corroboration</button></div><div class="card"><h2>Status</h2><pre id="status">loading...</pre></div></div><script>async function refresh(){const r=await fetch('/api/status');const j=await r.json();document.getElementById('status').textContent=JSON.stringify(j,null,2)} async function runDemo(){await fetch('/api/demo/corroborate',{method:'POST'});await refresh()} async function pollNow(){await fetch('/api/poll',{method:'POST'});await refresh()} refresh(); setInterval(refresh,3000);</script></body></html>`
